---
import BaseLayout from '../layouts/BaseLayout.astro';
import { getAllPosts } from '../lib/posts';
import { getAllDemos } from '../lib/demos';
import PostCard from '../components/blog/PostCard.astro';

const recentPosts = (await getAllPosts()).slice(0, 3);
const demos = await getAllDemos();

const domains = ['Antennas & Arrays', 'Photonics & Optics', 'RF & Transmission Lines', 'Signal Processing & DSP'];
---

<BaseLayout title="frah90 — Engineering Portfolio">
  <!-- Hero -->
  <section class="max-w-5xl mx-auto px-4 pt-20 pb-16">
    <p class="text-emerald-400 font-mono text-sm mb-3">hi, I'm FraH</p>
    <h1 class="text-4xl sm:text-6xl font-bold text-zinc-50 leading-tight mb-6">
      Electronics &<br />Photonics Engineer
    </h1>
    <p class="text-zinc-400 text-lg max-w-2xl mb-8">
      I work at the intersection of antenna systems, RF engineering, photonics, and signal processing.
      This site is where I document what I know through interactive demos and technical writing.
    </p>
    <div class="flex flex-wrap gap-3">
      <a href="/demos" class="px-5 py-2.5 bg-emerald-500 hover:bg-emerald-400 text-zinc-950 font-semibold rounded transition-colors text-sm">
        Explore Demos
      </a>
      <a href="/about" class="px-5 py-2.5 border border-zinc-700 hover:border-zinc-500 text-zinc-300 hover:text-zinc-100 rounded transition-colors text-sm">
        About Me
      </a>
    </div>
  </section>

  <!-- Domains -->
  <section class="max-w-5xl mx-auto px-4 py-12 border-t border-zinc-800">
    <h2 class="text-xs font-mono uppercase tracking-widest text-zinc-500 mb-6">Domains</h2>
    <div class="grid grid-cols-2 sm:grid-cols-4 gap-3">
      {domains.map(d => (
        <div class="border border-zinc-800 rounded-lg p-4 text-sm text-zinc-300 font-mono hover:border-zinc-600 transition-colors">
          {d}
        </div>
      ))}
    </div>
  </section>

  <!-- Featured Demos -->
  {demos.length > 0 && (
    <section class="max-w-5xl mx-auto px-4 py-12 border-t border-zinc-800">
      <div class="flex items-center justify-between mb-6">
        <h2 class="text-xs font-mono uppercase tracking-widest text-zinc-500">Interactive Demos</h2>
        <a href="/demos" class="text-xs font-mono text-emerald-400 hover:underline">view all →</a>
      </div>
      <div class="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
        {demos.slice(0, 3).map(demo => (
          <a
            href={`/demos/${demo.id}`}
            class="border border-zinc-800 rounded-lg p-5 hover:border-zinc-600 transition-colors group"
          >
            <span class="text-xs font-mono text-zinc-500 mb-2 block">{demo.data.domain}</span>
            <h3 class="text-sm font-semibold text-zinc-200 group-hover:text-emerald-400 transition-colors mb-1">
              {demo.data.title}
            </h3>
            <p class="text-xs text-zinc-500">{demo.data.description}</p>
          </a>
        ))}
      </div>
    </section>
  )}

  <!-- Recent Posts -->
  {recentPosts.length > 0 && (
    <section class="max-w-5xl mx-auto px-4 py-12 border-t border-zinc-800">
      <div class="flex items-center justify-between mb-6">
        <h2 class="text-xs font-mono uppercase tracking-widest text-zinc-500">Recent Posts</h2>
        <a href="/blog" class="text-xs font-mono text-emerald-400 hover:underline">view all →</a>
      </div>
      <div class="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
        {recentPosts.map(post => (
          <PostCard
            title={post.data.title}
            date={post.data.date}
            category={post.data.category}
            description={post.data.description}
            slug={post.id}
            tags={post.data.tags}
          />
        ))}
      </div>
    </section>
  )}
</BaseLayout>

