  const yData = showdB ? AFdB : AF;
  const yLabel = showdB ? '|AF| dB' : '|AF| normalized';

  const steeringAngle = beta !== 0
    ? ((Math.acos(-beta / (2 * Math.PI * d)) * 180) / Math.PI).toFixed(1)
    : '90.0';

  return (
    <div className="flex flex-col gap-6">
      {/* Sliders */}
